// test/functional/core/DiContainer.functional.test.js

const assert = require('assert');
const DiContainer = require('../../../src/core/DiContainer');

describe('DiContainer (Functional)', () => {
  before(() => DiContainer.reset());

  it('should support property injection via annotation simulation', () => {
    class UserRepository {
      getUser(id) {
        return { id, name: 'Udo' };
      }
    }

    class UserService {
      constructor() {
        this.repo = DiContainer.resolve('UserRepository');
      }

      getUser(id) {
        return this.repo.getUser(id);
      }
    }

    DiContainer.register('UserRepository', UserRepository);
    DiContainer.register('UserService', UserService);

    const service = DiContainer.resolve('UserService');
    const user = service.getUser(1);

    assert.deepStrictEqual(user, { id: 1, name: 'Udo' });
  });
});